  ],
  "steps": [
    {
      "order": 1,
      "title": "소고기 볶아 밑준비하기",
      "description": [
        {
          "content": "냄비에 소고기 양지 1/2컵(100g)을 넣어주세요.",
          "start": "00:02:48",
          "end": "00:02:53"
        },
        {
          "content": "참기름 2큰술(14g)을 냄비에 넣어주세요.",
          "start": "00:02:53",
          "end": "00:02:58"
        },
        {
          "content": "소고기의 겉면이 익고 붉은색이 없어질 때까지 충분히 볶아주세요.",
          "start": "00:03:00",
          "end": "00:03:18"
        }
      ],
      "scenes": [
        {
          "start": "00:03:04",
          "end": "00:03:14",
          "label": "붉은색이 없어질 때까지"
        }
      ],
      "timerSeconds": null
    },
    {
      "order": 2,
      "title": "미역과 국간장 넣고 볶기",
      "description": [
        {
          "content": "불린 미역을 체에 받쳐 물기를 완전히 제거해주세요.",
          "start": "00:03:32",
          "end": "00:03:40"
        },
        {
          "content": "물기를 뺀 미역 1/3컵(10g)을 냄비에 넣어주세요.",
          "start": "00:03:46",
          "end": "00:03:52"
        },
        {
          "content": "소고기와 미역이 잘 어우러지도록 함께 볶아주세요.",
          "start": "00:03:52",
          "end": "00:04:16"
        },
        {
          "content": "국간장 3큰술(30g)을 넣어 소고기와 미역에 간이 깊게 배도록 볶아주세요.",
          "start": "00:04:26",
          "end": "00:04:43"
        }
      ],
      "scenes": [
        {
          "start": "00:03:35",
          "end": "00:03:39",
          "label": "미역 물기 제거"
        },
        {
          "start": "00:03:55",
          "end": "00:04:08",
          "label": "함께 볶아주세요"
        },
        {
          "start": "00:04:32",
          "end": "00:04:41",
          "label": "간이 깊게 배도록"
        }
      ],
      "timerSeconds": null
    },
    {
      "order": 3,
      "title": "물 붓고 끓이기",
      "description": [
        {
          "content": "물 약 7컵(1.3L)을 냄비에 부어주세요.",
          "start": "00:04:56",
          "end": "00:05:03"
        },
        {
          "content": "국물이 우러나도록 중불에서 충분히 끓여주세요.",
          "start": "00:05:14",
          "end": "00:05:19"
        }
      ],
      "scenes": [
        {
          "start": "00:05:14",
          "end": "00:05:19",
          "label": "중불에서 끓이기"
        }
      ],
      "timerSeconds": 46
    },
    {
      "order": 4,
      "title": "미역 크기 조절하기",
      "description": [
        {
          "content": "미역의 크기가 너무 크다면 가위를 이용해 먹기 좋은 크기로 잘라주세요.",
          "start": "00:06:05",
          "end": "00:06:14"
        }
      ],
      "scenes": [
        {
          "start": "00:06:06",
          "end": "00:06:12",
          "label": "가위로 잘라주세요"
        }
      ],
      "timerSeconds": null
    },
    {
      "order": 5,
      "title": "마늘과 액젓으로 간 맞추기",
      "description": [
        {
          "content": "간 마늘 2/3큰술(10g)을 넣고 저어주세요.",
          "start": "00:06:32",
          "end": "00:06:40"
        },
        {
          "content": "국물 맛을 본 후 부족한 간은 국간장을 추가하여 맞춰주세요.",
          "start": "00:07:02",
          "end": "00:07:07"
        },
        {
          "content": "멸치액젓 1과 1/2큰술(15g)을 넣어 감칠맛과 풍미를 더해주세요.",
          "start": "00:07:12",
          "end": "00:07:17"
        }
      ],
      "scenes": [],
      "timerSeconds": null
    },
    {
      "order": 6,
      "title": "그릇에 담아 완성하기",
      "description": [
        {
          "content": "완성된 소고기 미역국을 그릇에 정성스럽게 담아내세요.",
          "start": "00:08:46",
          "end": "00:09:00"
        }
      ],
      "scenes": [],
      "timerSeconds": null
    }
  ],
  "servingTip": null
